'use client';

import { useRef, useState, useEffect } from 'react';
import Image from 'next/image';
import gsap from 'gsap';

/* ─────────────────── Image Pool ─────────────────── */
const POOL = [
  { src: 'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&q=80&w=2560', title: 'Modern Minimalist' },
  { src: 'https://images.unsplash.com/photo-1618221195710-dd6b41faaea6?auto=format&fit=crop&q=80&w=2560', title: 'Classic Elegance' },
  { src: 'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?auto=format&fit=crop&q=80&w=2560', title: 'Bohemian Chic' },
  { src: 'https://images.unsplash.com/photo-1542889601-399c4f3a8402?auto=format&fit=crop&q=80&w=2560', title: 'Industrial Urban' },
  { src: 'https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?auto=format&fit=crop&q=80&w=2560', title: 'Luxury Villa' },
  { src: 'https://images.unsplash.com/photo-1512917774080-9991f1c4c750?auto=format&fit=crop&q=80&w=2560', title: 'Contemporary Home' },
  { src: 'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=2560', title: 'Corporate Office' },
  { src: 'https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&q=80&w=2560', title: 'Estate Living' },
  { src: 'https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?auto=format&fit=crop&q=80&w=2560', title: 'Art Deco Suite' },
  { src: 'https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&q=80&w=2560', title: 'Penthouse View' },
];

/* ─────────────────── Layout Constants ─────────────────── */
// 7 cards total: index 0 = buffer-left (hidden), 1-5 = visible, 6 = buffer-right (hidden)
// Card center at index 3 → visual center of the 5 visible cards
const STEP    = 19;     // % distance between card left edges
const WIDTH   = 15;     // % width of each card
const OFFSET  = -14.5;  // % left position of index 0 (off-screen)
// Computed: i=3 → left = 3*19 - 14.5 = 42.5%, center at 42.5 + 7.5 = 50% ✓

const SLIDE_MS = 800;
const FLY_MS   = 850;
const OVERLAP  = 0.75;  // fly starts at 75% of slide
const PAUSE_MS = 2200;

/* ─────────────────── Types ─────────────────── */
type Card      = { src: string; title: string; uid: number };
type HeroLayer = { src: string; title: string; uid: number; z: number };

/* ─────────────────── Component ─────────────────── */
export default function HeroSection({ clinic, media }: { clinic: any; media: any }) {
  /* ── Refs ── */
  const sectionRef   = useRef<HTMLElement>(null);
  const heroRef      = useRef<HTMLDivElement>(null);
  const carouselRef  = useRef<HTMLDivElement>(null);
  const mountedRef   = useRef(true);
  const startedRef   = useRef(false);
  const uidRef       = useRef(0);
  const poolIdxRef   = useRef(0);
  const heroZRef     = useRef(10);

  /* ── State ── */
  const [cards, setCards]           = useState<Card[]>([]);
  const [heroLayers, setHeroLayers] = useState<HeroLayer[]>([]);

  /* ── Helpers ── */
  const nextUid = () => ++uidRef.current;
  const nextFromPool = () => {
    const img = POOL[poolIdxRef.current % POOL.length];
    poolIdxRef.current++;
    return img;
  };

  /* ─────────────────── Bootstrap ─────────────────── */
  useEffect(() => {
    const init: Card[] = [];
    for (let i = 0; i < 7; i++) {
      const img = POOL[i % POOL.length];
      init.push({ src: img.src, title: img.title, uid: nextUid() });
    }
    poolIdxRef.current = 7;
    setCards(init);
    // Hero starts empty — first fly-up will populate it
  }, []);

  useEffect(() => {
    mountedRef.current = true;
    return () => { mountedRef.current = false; };
  }, []);

  /* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
     FLIP Fly-Up Animation
     ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
  function flyUp(cardIndex: number, onLand: () => void) {
    const section  = sectionRef.current;
    const hero     = heroRef.current;
    const carousel = carouselRef.current;
    if (!section || !hero || !carousel || !mountedRef.current) return;

    const cardEls = carousel.querySelectorAll<HTMLElement>('[data-hero-card]');
    const cardEl  = cardEls[cardIndex];
    if (!cardEl) return;
    const thumbEl = cardEl.querySelector<HTMLElement>('[data-thumb]');
    if (!thumbEl) return;

    /* ── Measure ── */
    const tR = thumbEl.getBoundingClientRect();
    const hR = hero.getBoundingClientRect();
    const sR = section.getBoundingClientRect();

    const imgSrc = thumbEl.querySelector('img')?.src || '';
    const title  = cardEl.getAttribute('data-title') || '';

    /* ── Create flyer at FINAL (hero) size & position ── */
    const flyer = document.createElement('div');
    const newZ  = ++heroZRef.current;
    const fL = hR.left - sR.left;
    const fT = hR.top  - sR.top;
    const fW = hR.width;
    const fH = hR.height;

    Object.assign(flyer.style, {
      position: 'absolute',
      left:     `${fL}px`,
      top:      `${fT}px`,
      width:    `${fW}px`,
      height:   `${fH}px`,
      zIndex:   String(newZ + 100),
      overflow: 'hidden',
      pointerEvents: 'none',
      transformOrigin: '0 0',
      willChange: 'transform',
    });

    flyer.innerHTML = `<img src="${imgSrc}" alt="" style="width:100%;height:100%;object-fit:cover;display:block;" />`;
    section.appendChild(flyer);

    /* ── FLIP: Invert — scale & translate to match thumb position ── */
    const scaleX = tR.width  / fW;
    const scaleY = tR.height / fH;
    const dx     = (tR.left - sR.left) - fL;
    const dy     = (tR.top  - sR.top)  - fT;

    gsap.set(flyer, {
      x: dx, y: dy,
      scaleX, scaleY,
      borderRadius: '16px',
      boxShadow: '0 4px 20px rgba(0,0,0,0.15)',
    });

    /* Hide original thumb instantly */
    thumbEl.style.opacity = '0';

    /* ── FLIP: Play — animate to identity (= hero size) ── */
    gsap.to(flyer, {
      x: 0, y: 0,
      scaleX: 1, scaleY: 1,
      borderRadius: '32px',
      boxShadow: '0 24px 64px rgba(0,0,0,0.35)',
      duration: FLY_MS / 1000,
      ease: 'power3.inOut',
      onComplete: () => {
        if (!mountedRef.current) return;

        /* Land: push onto hero stack (keep max 2), destroy flyer */
        setHeroLayers(prev =>
          [...prev, { src: imgSrc, title, uid: nextUid(), z: newZ }].slice(-2)
        );
        flyer.remove();

        /* Restore thumb with quick 0.2s fade */
        gsap.to(thumbEl, { opacity: 1, duration: 0.2, ease: 'power2.out' });

        onLand();
      },
    });
  }

  /* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
     Slide Carousel + Overlapping Fly-Up
     ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
  function slideAndFly() {
    if (!mountedRef.current) return;

    /* 1. Shift cards array → CSS transition handles the slide */
    setCards(prev => {
      const shifted = prev.slice(1);
      const img = nextFromPool();
      shifted.push({ src: img.src, title: img.title, uid: nextUid() });
      return shifted;
    });

    /* 2. Wait for React render, then schedule the fly-up at 75% of the slide */
    requestAnimationFrame(() => requestAnimationFrame(() => {
      if (!mountedRef.current) return;

      setTimeout(() => {
        if (!mountedRef.current) return;

        flyUp(3, () => {
          /* After landing, pause then repeat */
          setTimeout(() => {
            if (mountedRef.current) slideAndFly();
          }, PAUSE_MS);
        });
      }, SLIDE_MS * OVERLAP);
    }));
  }

  /* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
     Kick Off — Stage 2: First Pop-Out
     ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
  useEffect(() => {
    if (cards.length === 7 && !startedRef.current) {
      startedRef.current = true;
      const timer = setTimeout(() => {
        if (!mountedRef.current) return;
        /* Stage 2: First fly-up from center card (index 3) */
        flyUp(3, () => {
          /* After first fly lands → begin Stage 3 loop */
          setTimeout(() => {
            if (mountedRef.current) slideAndFly();
          }, 1500);
        });
      }, 1800);
      return () => clearTimeout(timer);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cards.length]);

  /* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
     Render
     ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
  return (
    <section
      ref={sectionRef}
      className="relative px-4 md:px-8 mt-6 mb-12"
      style={{ isolation: 'isolate' }}
    >
      <div
        className="max-w-7xl mx-auto relative w-full"
        style={{ height: 'clamp(520px, 72vh, 760px)' }}
      >

        {/* ─── Hero Display Area ─── */}
        <div
          ref={heroRef}
          className="hero-display"
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: 'calc(100% - 210px)',
            borderRadius: '32px',
            overflow: 'hidden',
            zIndex: 5,
            background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)',
          }}
        >
          {/* Empty state text */}
          {heroLayers.length === 0 && (
            <div className="absolute inset-0 flex items-center justify-center z-0">
              <p className="text-white/20 text-lg tracking-widest uppercase font-light">
                {clinic?.name || 'Discover Our Interiors'}
              </p>
            </div>
          )}

          {/* Stacked hero images */}
          {heroLayers.map(layer => (
            <div
              key={layer.uid}
              className="absolute inset-0"
              style={{ zIndex: layer.z }}
            >
              <Image
                src={layer.src}
                alt={layer.title}
                fill
                className="object-cover"
                sizes="(max-width: 768px) 100vw, 1280px"
                priority
                unoptimized
              />
              <div className="absolute inset-0 bg-gradient-to-t from-[#0f172a]/90 via-[#0f172a]/20 to-transparent" />
              <div className="absolute bottom-6 md:bottom-10 left-6 md:left-10 right-6 text-white z-10">
                <span className="inline-block px-3 py-1 mb-3 text-[0.65rem] font-semibold uppercase tracking-[0.2em] bg-white/15 backdrop-blur-sm rounded-full border border-white/20">
                  Featured
                </span>
                <h3 className="text-2xl md:text-5xl font-bold mb-2 md:mb-3 leading-tight">
                  {layer.title}
                </h3>
                <p className="text-white/80 max-w-md text-xs md:text-base leading-relaxed line-clamp-2">
                  Elevating modern interiors with thoughtful design and premium craftsmanship.
                </p>
              </div>
            </div>
          ))}
        </div>

        {/* ─── Bottom Carousel ─── */}
        <div
          ref={carouselRef}
          style={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            width: '100%',
            height: '210px',
            overflow: 'hidden',
            zIndex: 4,
          }}
        >
          {cards.map((card, i) => {
            const isCenter = i === 3;
            const leftPct  = OFFSET + i * STEP;

            return (
              <div
                key={card.uid}
                data-hero-card=""
                data-title={card.title}
                style={{
                  position: 'absolute',
                  left: `${leftPct}%`,
                  width: `${WIDTH}%`,
                  top: '8px',
                  bottom: '8px',
                  transition: `left ${SLIDE_MS}ms cubic-bezier(0.4, 0, 0.2, 1)`,
                  zIndex: isCenter ? 2 : 1,
                }}
              >
                {/* Card Body */}
                <div
                  style={{
                    display: 'flex',
                    flexDirection: 'column',
                    height: '100%',
                    borderRadius: '16px',
                    overflow: 'hidden',
                    background: '#ffffff',
                    boxShadow: isCenter
                      ? '0 8px 32px rgba(0,0,0,0.12), 0 2px 8px rgba(0,0,0,0.06)'
                      : '0 2px 12px rgba(0,0,0,0.06), 0 1px 3px rgba(0,0,0,0.04)',
                    border: isCenter
                      ? '2px solid rgba(37,99,235,0.18)'
                      : '1px solid rgba(0,0,0,0.06)',
                    transform: isCenter ? 'translateY(-6px) scale(1.04)' : 'scale(1)',
                    transition: 'transform 0.5s cubic-bezier(0.4,0,0.2,1), box-shadow 0.5s ease, border-color 0.5s ease',
                  }}
                >
                  {/* Image Thumbnail */}
                  <div
                    data-thumb=""
                    style={{
                      position: 'relative',
                      flex: '1 1 auto',
                      minHeight: 0,
                    }}
                  >
                    <Image
                      src={card.src}
                      alt={card.title}
                      fill
                      className="object-cover"
                      sizes="200px"
                      unoptimized
                    />
                  </div>

                  {/* Label Bar */}
                  <div
                    style={{
                      flex: '0 0 auto',
                      padding: '10px 10px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      borderTop: '1px solid rgba(0,0,0,0.05)',
                      background: isCenter ? 'rgba(37,99,235,0.03)' : 'transparent',
                      transition: 'background 0.4s ease',
                    }}
                  >
                    <span
                      style={{
                        fontSize: 'clamp(0.55rem, 0.7vw, 0.72rem)',
                        fontWeight: 600,
                        textTransform: 'uppercase',
                        letterSpacing: '0.08em',
                        color: isCenter ? '#1e3a5f' : '#94a3b8',
                        textAlign: 'center',
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        transition: 'color 0.4s ease',
                      }}
                    >
                      {card.title}
                    </span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

      </div>
    </section>
  );
}
